#include <stdio.h>
#include <stdlib.h>

int cmp_int(const void *a, const void *b) {
    int x = *(const int *)a;
    int y = *(const int *)b;
    return (x > y) - (x < y);
}

int lower_bound(int *arr, int size, int val) {
    int l = 0, r = size; // [l, r)
    while (l < r) {
        int m = l + (r - l) / 2;
        if (arr[m] >= val) r = m; else l = m + 1;
    }
    return l;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *tails = (int *)malloc(N * sizeof(int));
        int sz = 0;
        for (int i = 0; i < N; ++i) {
            int a; scanf("%d", &a);
            int x = -a; // transform
            int pos = lower_bound(tails, sz, x);
            if (pos == sz) {
                tails[sz++] = x;
            } else {
                tails[pos] = x;
            }
        }
        printf("%d\n", sz);
        free(tails);
    }
    return 0;
}

