        for(int i=0;i<N;++i){
            int a; cin>>a;
            int x = -a; // transform to LIS problem
            auto it = lower_bound(tails.begin(), tails.end(), x);
            if(it==tails.end()) tails.push_back(x);
            else *it = x;
        }
        cout << tails.size() << '\n';
    }
    return 0;
}

