import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        tails = []
        for _ in range(N):
            a = next(it)
            x = -a  # transform
            # binary search lower_bound
            lo, hi = 0, len(tails)
            while lo < hi:
                mid = (lo + hi) // 2
                if tails[mid] >= x:
                    hi = mid
                else:
                    lo = mid + 1
            if lo == len(tails):
                tails.append(x)
            else:
                tails[lo] = x
        out_lines.append(str(len(tails)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

