  const N = input[idx++];
  const tails = [];
  for (let i = 0; i < N; ++i) {
    const a = input[idx++];
    const x = -a; // transform
    // lower_bound on tails (sorted increasingly)
    let l = 0, r = tails.length;
    while (l < r) {
      const m = (l + r) >> 1;
      if (tails[m] >= x) r = m; else l = m + 1;
    }
    if (l === tails.length) tails.push(x);
    else tails[l] = x;
  }
  outputs.push(String(tails.length));
}
